import 'package:flutter/material.dart';

// ============ MODEL ============
class User {
  const User({required this.id, required this.name});
  final int id;
  final String name;
}

// Repository — the boundary between ViewModel and the outside world (network, DB).
class UserRepository {
  Future<User> fetch(int id) async {
    await Future.delayed(const Duration(milliseconds: 500));
    return User(id: id, name: 'User $id');
  }
}

// ============ VIEW MODEL ============
// A ChangeNotifier is the simplest ViewModel — mutable UI-shaped state
// with a `notifyListeners()` broadcast on change.
class UserViewModel extends ChangeNotifier {
  UserViewModel(this._repo);
  final UserRepository _repo;

  // UI-consumable state — the View reads THESE fields, not the Model directly.
  bool _loading = false;
  User? _user;
  String? _error;

  bool get loading => _loading;
  User? get user => _user;
  String? get error => _error;

  // Input handlers — View calls these; ViewModel decides what to do.
  Future<void> loadUser(int id) async {
    _loading = true; _error = null; notifyListeners();
    try {
      _user = await _repo.fetch(id);
    } catch (e) {
      _error = e.toString();
    } finally {
      _loading = false; notifyListeners();
    }
  }

  void clear() {
    _user = null; _error = null; notifyListeners();
  }
}

// ============ VIEW ============
class UserScreen extends StatefulWidget {
  const UserScreen({super.key});
  @override State<UserScreen> createState() => _UserScreenState();
}

class _UserScreenState extends State<UserScreen> {
  late final _vm = UserViewModel(UserRepository());

  @override
  void initState() {
    super.initState();
    _vm.addListener(_rebuild);
    _vm.loadUser(42);   // kick off the initial load
  }

  @override
  void dispose() { _vm.removeListener(_rebuild); _vm.dispose(); super.dispose(); }

  void _rebuild() => setState(() {});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('MVVM demo')),
    body: Center(
      child: _vm.loading
          ? const CircularProgressIndicator()
          : _vm.error != null
              ? Text('Error: ${_vm.error}')
              : Text('Hi, ${_vm.user?.name}',
                  style: const TextStyle(fontSize: 24)),
    ),
    floatingActionButton: FloatingActionButton(
      onPressed: () => _vm.loadUser(43),   // View delegates to ViewModel
      child: const Icon(Icons.refresh),
    ),
  );
}

void main() => runApp(const MaterialApp(home: UserScreen()));

// The View never calls the Repository. It never mutates the User. It reads
// state from the ViewModel and forwards taps back. Business rules live in
// the ViewModel (and its Repository). Migration to Provider, Riverpod, Bloc,
// or MobX is a mechanical exercise — the same ViewModel, wrapped differently.
